compliant:
#include <format>  // C++20
#include <print>   // C++23
#include <iostream>

int age = 25;
std::string name = "John";

// Compliant: Using C++ formatting (C++20)
std::string message = std::format("Hello {}, you are {} years old\n", name, age);

// Compliant: Using C++ print (C++23)
std::print("Hello {}, you are {} years old\n", name, age);

// Compliant: Traditional C++ streams
std::cout << "Hello " << name << ", you are " << age << " years old\n";
